var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래시포드 씨. 저희는 무사히 설치 끝냈어요.","JPN":"ラッシュフォードさん。こちらは無事設置を完了しましたよ。","ENG":"Miss Rashford. We're all set up here.","TWN":"雷斯福特，我們已經順利設置完畢。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이쪽도 문제없습니다. 그럼 바로 작동시켜 보죠.","JPN":"こちらも問題ありません。それでは作動させてみましょう。","ENG":"No problems here. Let's get them online.","TWN":"這邊也沒問題，那就立刻啓動吧。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"뭐지……?","JPN":"何だ……？","ENG":"What...?","TWN":"怎麼會……？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이상해. 침식파가 약해지는 구간이 전혀 보이지 않아.","JPN":"おかしい。侵食波が弱まる区間がまったく見当たらない。","ENG":"Something's not right. There isn't a place where the Corruption ray weakens.","TWN":"奇怪，完全看不到侵蝕波變弱的區段。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"심지어 한 곳은… 침식파가 비정상적으로 집중되어 있어.","JPN":"しかも一か所は……侵食波が異常に集中している。","ENG":"But there's one place... where the Corruption ray is abnormally strong.","TWN":"甚至有一個地方…侵蝕波異常集中。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"저… 래시포드 씨?","JPN":"あの……ラッシュフォードさん？","ENG":"Um... Miss Rashford?","TWN":"那個… 雷斯福特？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어쩌면 고준위 침식파가 흐르는 좌표에 성유물이 있는 게 아닐까요?","JPN":"もしかしたら、高レベルの侵食波が流れてる座標に聖遺物があるんじゃないでしょうか？","ENG":"What if the coordinates where the Corruption ray is focusing is where the Holy Relic is?","TWN":"聖遺物會不會就在高段侵蝕波流動的座標？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…네? 그게 무슨 말씀이시죠?","JPN":"……はい？　それはどういうことですか？","ENG":"Huh? What do you meant by that?","TWN":"……嗯？那是什麼意思？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"성유물은 침식을 막아 주던 도구라고 들었어요.","JPN":"聖遺物は侵食を防いでいた道具だと聞きました。","ENG":"I heard that the Holy Relic was a tool used to block out Corruption.","TWN":"我聽說聖遺物是抵擋侵蝕的工具。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"이건 가정일 뿐이지만… 그 원리가 침식파를 흡수하기 때문이라면, 오히려 침식파가 강한 곳이 정답일 수도 있겠다는 생각이 들어서요.","JPN":"これは推測ですけど……その原理が侵食波を吸収するためだったら、むしろ侵食波が強い場所が正解かもしれないと思ったんです。","ENG":"It's just a hypothesis, but... What if it prevented the Corruption ray by absorbing it? That would explain why it's abnormally strong in that place.","TWN":"雖然這只是假設…如果其原理是吸收侵蝕波，那侵蝕波強的地方或許反而有正確答案。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그렇게 생각하면 침식파가 높은 이유도 납득이 가는군요.","JPN":"そう考えれば侵食波のレベルが高い理由も納得できますね。","ENG":"That could explain why...","TWN":"這樣的話，似乎也能理解侵蝕波高的理原因。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지금으로선 달리 특정할 만한 장소가 없으니, 한나 씨의 의견을 따라서…","JPN":"現時点では別に特定できる場所がないし、ハンナさんの意見に従って……","ENG":"Then, since there is no other location we can pinpoint, let's follow Hanna's suggestion and–","TWN":"現在沒什麼特別鎖定的地方，就照漢娜的意思…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"장교님! 조심하십시오!","JPN":"将校！　お気をつけください！","ENG":"Officer Rashford! Watch out!","TWN":"軍官！請小心！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…음?","JPN":"……む？","ENG":"Hmm?","TWN":"…嗯？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"큭…?!","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"唔…？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};